import os
import logging
from google.cloud import storage, firestore, pubsub_v1

def process_file(data, context):
    # Get file metadata from Cloud Storage event
    bucket_name = data['bucket']
    file_name = data['name']

    # Download file from Cloud Storage
    client = storage.Client()
    bucket = client.get_bucket(bucket_name)
    blob = bucket.blob(file_name)
    file_data = blob.download_as_string()

    # Write to Firestore
    db = firestore.Client()
    doc_ref = db.collection('files').document(file_name)
    doc_ref.set({'data': file_data})

    # Publish to Pub/Sub
    publisher = pubsub_v1.PublisherClient()
    topic_path = 'your-project-id/topics/your-topic-name'
    publisher.publish(topic_path, data=file_data)

# Set up service account credentials
os.environ['GOOGLE_APPLICATION_CREDENTIALS'] = '/path/to/service_account_key.json'

# Set up logging
logging.basicConfig(level=logging.INFO)